                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                            </small>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mb-0 mt-1">@entry.Description</p>
                            }
                        </div>
                    }
                </div>

                @* References *@
                <div class="mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>References</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    <hr class="mt-1" />
                    @foreach (var r in references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> (@r.Relationship)<br />
                            <small>@r.Email &bull; @r.Phone</small>
                        </div>
                    }
                </div>

                @* Cover Letter *@
                <div class="mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Cover Letter</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(4)">Edit</button>
                    </div>
                    <hr class="mt-1" />
                    <p style="white-space:pre-wrap;">@coverLetter</p>
                </div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => currentStep = 4">Back</button>
                    <button class="btn btn-success" @onclick="SubmitApplication" disabled="@isLoading">
                        @if (isLoading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Submit Application
                    </button>
                </div>
            </div>
        </div>
    }

    @* ───── Confirmation ───── *@
    @if (isSubmitted)
    {
        <div class="card border-success">
            <div class="card-body text-center py-5">
                <div class="text-success mb-3" style="font-size:3rem;">&#10003;</div>
                <h4 class="text-success">Application Submitted!</h4>
                <p class="lead">Your application ID is <strong>#@applicationId</strong></p>
                <p class="text-muted">Thank you for applying. We will review your application and get back to you soon.</p>
            </div>
        </div>
    }
</div>

@code {
    private static readonly string[] StepLabels = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int currentStep = 1;
    private bool isLoading;
    private bool isSubmitted;
    private int applicationId;
    private string? errorMessage;

    // Step 1
    private string fullName = string.Empty;
    private string email = string.Empty;
    private string phone = string.Empty;
    private string address = string.Empty;

    // Step 2
    private List<WorkEntryForm> workEntries = new() { new() };

    // Step 3
    private List<ReferenceForm> references = new() { new(), new() };

    // Step 4
    private string coverLetter = string.Empty;

    // --- Mutable form models (records are immutable, so we use classes internally) ---

    private class WorkEntryForm
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private class ReferenceForm
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }

    // --- Step indicator helpers ---

    private string StepBadgeClass(int step)
    {
        if (step == currentStep) return "btn-primary";
        if (step < currentStep) return "btn-success";
        return "btn-outline-secondary";
    }

    private void GoToStep(int step)
    {
        if (step < currentStep && !isSubmitted)
        {
            errorMessage = null;
            currentStep = step;
        }
    }

    // --- Step 1 ---

    private async Task NextFromPersonalInfo()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email)
            || string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }

        isLoading = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(email);
            if (!valid)
            {
                errorMessage = "Please enter a valid email address.";
                return;
            }
            currentStep = 2;
        }
        finally
        {
            isLoading = false;
        }
    }

    // --- Step 2 ---

    private void AddWorkEntry() => workEntries.Add(new WorkEntryForm());

    private void RemoveWorkEntry(int index)
    {
        if (workEntries.Count > 1)
            workEntries.RemoveAt(index);
    }

    private void UpdateWork(int index, WorkEntryForm updated) => workEntries[index] = updated;

    private void NextFromWorkHistory()
    {
        errorMessage = null;

        foreach (var entry in workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                errorMessage = "Please fill in company and job title for all positions.";
                return;
            }
        }

        currentStep = 3;
    }

    // --- Step 3 ---

    private void AddReference()
    {
        if (references.Count < 3)
            references.Add(new ReferenceForm());
    }

    private void RemoveReference(int index)
    {
        if (references.Count > 2)
            references.RemoveAt(index);
    }

    private void UpdateRef(int index, ReferenceForm updated) => references[index] = updated;

    private void NextFromReferences()
    {
        errorMessage = null;

        foreach (var r in references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }

        currentStep = 4;
    }

    // --- Step 5 ---

    private async Task SubmitApplication()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var personal = new PersonalInfo(fullName, email, phone, address);
            var work = new WorkHistory(workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var refs = references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, work, refs, coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    // --- Date helpers ---

    private static string FormatDate(DateTime date) => date.ToString("yyyy-MM-dd");

    private static string? FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd");

    private static DateTime ParseDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : DateTime.Today;

    private static DateTime? ParseNullableDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : null;
}

