{"file_text": "@page "/apply"
@rendermode InteractiveServer
@using sv_b4f325df25ce433a885c5ef9f58c9d62.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="d-flex justify-content-between mb-4 position-relative">
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var step = i + 1;
            var isCurrent = step == currentStep;
            var isCompleted = step < currentStep;
            var isFuture = step > currentStep;

            <div class="text-center flex-fill position-relative">
                <button class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepBadgeClass(step)"
                        style="width:36px;height:36px;font-size:.85rem;"
                        disabled="@(isFuture || isSubmitted)"
                        @onclick="() => GoToStep(step)">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @step
                    }
                </button>
                <div class="small mt-1 @(isFuture ? "text-muted" : "")" style="@(isCurrent ? "font-weight:600;" : "")">
                    @StepLabels[i]
                </div>
            </div>
        }
    </nav>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @* ───── Step 1: Personal Info ───── *@
    @if (currentStep == 1)
    {
        <div class="card">
            <div class="card-body">
                <h4 class="card-title mb-3">Personal Information</h4>

                <div class="mb-3">
                    <label class="form-label">Full Name <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="fullName" placeholder="Jane Doe" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="email" placeholder="jane@example.com" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="phone" placeholder="(555) 123-4567" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Address <span class="text-danger">*</span></label>
                    <textarea class="form-control" rows="2" @bind="address" placeholder="123 Main St, City, State ZIP"></textarea>
                </div>

                <div class="d-flex justify-content-end">
                    <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@isLoading">
                        @if (isLoading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Next
                    </button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 2: Work History ───── *@
    @if (currentStep == 2)
    {
        <div class="card">
            <div class="card-body">
                <h4 class="card-title mb-3">Work History</h4>

                @for (int i = 0; i < workEntries.Count; i++)
                {
                    var idx = i;
                    var entry = workEntries[idx];

                    <div class="border rounded p-3 mb-3">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Position @(idx + 1)</h6>
                            @if (workEntries.Count > 1)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                            }
                        </div>

                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Company <span class="text-danger">*</span></label>
                                <input class="form-control" value="@entry.Company"
                                       @onchange="e => UpdateWork(idx, entry with { Company = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                <input class="form-control" value="@entry.Title"
                                       @onchange="e => UpdateWork(idx, entry with { Title = (string?)e.Value ?? string.Empty })" />
                            </div>
                        </div>

                        <div class="row mb-2">
                            <div class="col-md-4">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                                       @onchange="e => UpdateWork(idx, entry with { StartDate = ParseDate((string?)e.Value) })" />
                            </div>
                            <div class="col-md-4">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                                       disabled="@entry.IsCurrent"
                                       @onchange="e => UpdateWork(idx, entry with { EndDate = ParseNullableDate((string?)e.Value) })" />
                            </div>
                            <div class="col-md-4 d-flex align-items-end pb-1">
                                <div class="form-check">
                                    <input type="checkbox" class="form-check-input" id="@($"current-{idx}")"
                                           checked="@entry.IsCurrent"
                                           @onchange="e => UpdateWork(idx, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                                    <label class="form-check-label" for="@($"current-{idx}")">Currently employed</label>
                                </div>
                            </div>
                        </div>

                        <div class="mb-0">
                            <label class="form-label">Description</label>
                            <textarea class="form-control" rows="2" value="@entry.Description"
                                      @onchange="e => UpdateWork(idx, entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
                        </div>
                    </div>
                }

                <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">
                    + Add Another Position
                </button>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => currentStep = 1">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 3: References ───── *@
    @if (currentStep == 3)
    {
        <div class="card">
            <div class="card-body">
                <h4 class="card-title mb-3">References</h4>

                @for (int i = 0; i < references.Count; i++)
                {
                    var idx = i;
                    var refEntry = references[idx];

                    <div class="border rounded p-3 mb-3">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Reference @(idx + 1)</h6>
                            @if (references.Count > 2)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(idx)">Remove</button>
                            }
                        </div>

                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input class="form-control" value="@refEntry.Name"
                                       @onchange="e => UpdateRef(idx, refEntry with { Name = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input class="form-control" value="@refEntry.Relationship"
                                       @onchange="e => UpdateRef(idx, refEntry with { Relationship = (string?)e.Value ?? string.Empty })" />
                            </div>
                        </div>

                        <div class="row">
                            <div class="col-md-6">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" value="@refEntry.Email"
                                       @onchange="e => UpdateRef(idx, refEntry with { Email = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" value="@refEntry.Phone"
                                       @onchange="e => UpdateRef(idx, refEntry with { Phone = (string?)e.Value ?? string.Empty })" />
                            </div>
                        </div>
                    </div>
                }

                @if (references.Count < 3)
                {
                    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                        + Add Reference
                    </button>
                }

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => currentStep = 2">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 4: Cover Letter ───── *@
    @if (currentStep == 4)
    {
        <div class="card">
            <div class="card-body">
                <h4 class="card-title mb-3">Cover Letter</h4>

                <div class="mb-2">
                    <textarea class="form-control" rows="10" maxlength="2000"
                              @bind="coverLetter" @bind:event="oninput"
                              placeholder="Write your cover letter here..."></textarea>
                </div>
                <div class="text-muted small mb-3">@(coverLetter?.Length ?? 0) / 2000 characters</div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => currentStep = 3">Back</button>
                    <button class="btn btn-primary" @onclick="() => currentStep = 5">Next</button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 5: Review & Submit ───── *@
    @if (currentStep == 5 && !isSubmitted)
    {
        <div class="card">
            <div class="card-body">
                <h4 class="card-title mb-3">Review &amp; Submit</h4>

                @* Personal Info *@
                <div class="mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Personal Information</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(1)">Edit</button>
                    </div>
                    <hr class="mt-1" />
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@fullName</dd>
                        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@email</dd>
                        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@phone</dd>
                        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@address</dd>
                    </dl>
                </div>

                @* Work History *@
                <div class="mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Work History</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(2)">Edit</button>
                    </div>
                    <hr class="mt-1" />
                    @foreach (var entry in workEntries)
                    {
                        <div class="mb-2">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <small class="text-muted">
                                @entry.StartDate.ToString("MMM yyyy") &mdash;
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                            </small>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mb-0 mt-1">@entry.Description</p>
                            }
                        </div>
                    }
                </div>

                @* References *@
                <div class="mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>References</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    <hr class="mt-1" />
                    @foreach (var r in references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> (@r.Relationship)<br />
                            <small>@r.Email &bull; @r.Phone</small>
                        </div>
                    }
                </div>

                @* Cover Letter *@
                <div class="mb-4">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Cover Letter</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(4)">Edit</button>
                    </div>
                    <hr class="mt-1" />
                    <p style="white-space:pre-wrap;">@coverLetter</p>
                </div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => currentStep = 4">Back</button>
                    <button class="btn btn-success" @onclick="SubmitApplication" disabled="@isLoading">
                        @if (isLoading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Submit Application
                    </button>
                </div>
            </div>
        </div>
    }

    @* ───── Confirmation ───── *@
    @if (isSubmitted)
    {
        <div class="card border-success">
            <div class="card-body text-center py-5">
                <div class="text-success mb-3" style="font-size:3rem;">&#10003;</div>
                <h4 class="text-success">Application Submitted!</h4>
                <p class="lead">Your application ID is <strong>#@applicationId</strong></p>
                <p class="text-muted">Thank you for applying. We will review your application and get back to you soon.</p>
            </div>
        </div>
    }
